#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-20

# Test scripts/check-install.sh — verifies the install preflight.
#
# Two cases:
#   (1) node_modules missing → exit 1 + actionable stderr
#   (2) node_modules present → exit 0 silent

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
SCRIPT_PATH="$PROJECT_ROOT/scripts/check-install.sh"

if [ ! -x "$SCRIPT_PATH" ]; then
  echo "FAIL: $SCRIPT_PATH not found or not executable" >&2
  exit 1
fi

# ----- helpers -----
PASS=0
FAIL=0
report_pass() { PASS=$((PASS+1)); echo "  PASS: $1"; }
report_fail() { FAIL=$((FAIL+1)); echo "  FAIL: $1" >&2; }

# ----- setup: copy the script into a temp project tree -----
TMPDIR_FAKE="$(mktemp -d)"
trap 'rm -rf "$TMPDIR_FAKE"' EXIT
mkdir -p "$TMPDIR_FAKE/scripts"
cp "$SCRIPT_PATH" "$TMPDIR_FAKE/scripts/check-install.sh"
chmod +x "$TMPDIR_FAKE/scripts/check-install.sh"

# ----- case 1: missing node_modules -----
echo "Test 1: missing node_modules should exit 1"
set +e
out="$("$TMPDIR_FAKE/scripts/check-install.sh" 2>&1)"
rc=$?
set -e

if [ "$rc" -ne 1 ]; then
  report_fail "expected exit 1, got $rc"
elif ! echo "$out" | grep -q "node_modules is missing"; then
  report_fail "stderr did not mention 'node_modules is missing'"
elif ! echo "$out" | grep -q "npm install"; then
  report_fail "stderr did not mention 'npm install'"
else
  report_pass "missing node_modules → exit 1 with actionable message"
fi

# ----- case 2: present node_modules -----
echo "Test 2: present node_modules should exit 0 silently"
mkdir -p "$TMPDIR_FAKE/node_modules"
set +e
out="$("$TMPDIR_FAKE/scripts/check-install.sh" 2>&1)"
rc=$?
set -e

if [ "$rc" -ne 0 ]; then
  report_fail "expected exit 0, got $rc"
elif [ -n "$out" ]; then
  report_fail "expected silent stdout/stderr, got: $out"
else
  report_pass "present node_modules → exit 0 silently"
fi

# ----- summary -----
echo ""
echo "─── Results ───"
echo "  PASS: $PASS"
echo "  FAIL: $FAIL"

if [ "$FAIL" -gt 0 ]; then
  exit 1
fi
